using System.Numerics;

namespace InFalsus.Crypto;

/// <summary>
/// Calculate Secret Unsigned Numbers.
/// </summary>
public static class SecretNumbers
{
    private static readonly BigInteger Int4096Mask =
        (BigInteger.One << 4096) - 1;

    private static readonly BigInteger ULongMask = (BigInteger.One << 64) - 1;

    private static readonly BigInteger Divider = BigInteger.Parse(
        "");

    private static readonly BigInteger[] Adders =
    [
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-"),
        BigInteger.Parse(
            ""),
        BigInteger.Parse(
            "-")
    ];

    public static ulong GetSecretUlong(int seed)
    {
        BigInteger curr = 0;
        BigInteger multiplier = seed;
        for (int i = Adders.Length - 1; i >= 0; i--)
        {
            curr = (curr * multiplier) & Int4096Mask;
            curr = (curr + Adders[i]) & Int4096Mask;
        }

        BigInteger value = curr / Divider;
        if (value.GetBitLength() > 64)
        {
            throw new ArgumentException(
                "invalid secret number, check your seed");
        }

        return (ulong)((curr / Divider) & ULongMask);
    }

    private static void AssertSecret(int seed, ulong expectedSecret)
    {
        if (GetSecretUlong(seed) != expectedSecret)
        {
            throw new ArgumentException("bad implementation");
        }
    }

    internal static void TestSecrets()
    {
        // From In Falsus Demo
        // Verified through metadata token calculation
        AssertSecret(1611115665, 12882194406589840563);
        AssertSecret(612309781, 17808699049056161141);
        AssertSecret(812456723, 17808699049056160649);
        AssertSecret(19892375, 17808699049056160651);
        AssertSecret(171223, 17808699049056160656);
        AssertSecret(9922334, 17808699049056160269);
        AssertSecret(36124152, 17808699049056160654);
        AssertSecret(78822233, 17808699049056160273);
        AssertSecret(12345678, 17808699049056160698);
    }
}